def threeSumClosest(nums, target):
    nums.sort()
    diff = float('inf')
    res = 0
    n = len(nums)
    for i in range(n):
        l, r = i + 1, n - 1
        while l < r:
            s = nums[i] + nums[l] + nums[r]
            if abs(target - s) < diff:
                diff = abs(target - s)
                res = s
            if s < target:
                l += 1
            elif s > target:
                r -= 1
            else:
                return s # Exact match found
    return res

