def minWindow(s, t):
    if not t or not s: return ""
    dictT = {}
    for c in t: dictT[c] = dictT.get(c, 0) + 1
    window = {}
    have, need = 0, len(dictT)
    res, res_len = [-1, -1], float('inf')
    l = 0
    for r, char in enumerate(s):
        if char in dictT:
            window[char] = window.get(char, 0) + 1
            if window[char] == dictT[char]: have += 1
        while have == need:
            if (r - l + 1) < res_len:
                res = [l, r]
                res_len = r - l + 1
            left_char = s[l]
            if left_char in dictT:
                window[left_char] -= 1
                if window[left_char] < dictT[left_char]: have -= 1
            l += 1
    l, r = res
    return s[l:r+1] if res_len != float('inf') else ""

